    startupName: 'Unnamed Startup',
    oneLiner: item.rawIdea,
    problemStatement: 'To be defined',
    proposedSolution: 'To be defined',
    primaryTargetAudience: 'General consumers',
    secondaryTargetAudience: 'N/A',
    coreValueProposition: 'To be defined',
    revenueModel: 'TBD',
    keyAssumptions: [],
