parameters.jsCode:
const item = $input.item.json;
let competitorData = {};
let demandData = {};

try {
  const compRaw = item.output || item.text || item.response || '{}';
  const compClean = compRaw.replace(/```json|```/g, '').trim();
  competitorData = JSON.parse(compClean);
} catch(e) {
  competitorData = { directCompetitors: [], indirectCompetitors: [], competitiveAdvantages: [], competitiveThreats: [], differentiationStrategy: 'TBD', moatPotential: 'medium', competitorScore: 5 };
}

try {
  const demandRaw = item.demandOutput || item.demandText || '{}';
  const demandClean = demandRaw.replace(/```json|```/g, '').trim();
  demandData = JSON.parse(demandClean);
} catch(e) {
  demandData = { demandSignals: [], validationMethods: [], riskFactors: [], productMarketFitScore: 5, pivotSuggestions: [], goToMarketRecommendation: 'TBD', overallViabilityScore: 5 };
}

const ideaScore = item.ideaScore || 5;
const marketScore = item.marketData?.marketResearchScore || 5;
const compScore = competitorData.competitorScore || 5;
const pmfScore = demandData.productMarketFitScore || 5;
const overallScore = Math.round((ideaScore + marketScore + compScore + pmfScore) / 4);

return {
  json: {
    ...item,
    competitorData,
    demandData,
    compositScore: overallScore,
    recommendation: overallScore >= 7 ? 'PROCEED' : overallScore >= 5 ? 'VALIDATE_FURTHER' : 'PIVOT_OR_ABANDON'
  }
};

