const item = $input.item.json;
const businessPlan = item.output || item.text || item.response || 'Business plan generation failed.';
const today = new Date().toISOString().split('T')[0];

return {
  json: {
    ...item,
    businessPlan,
    exportDate: today,
    status: 'Validated',
    summaryRow: [
      today,
      item.ideaId || 'N/A',
      item.startupName || 'Unknown',
      item.oneLiner || '',
      item.revenueModel || '',
      item.marketData?.totalAddressableMarket || '',
      (item.competitorData?.directCompetitors || []).length.toString(),
      (item.demandData?.productMarketFitScore || 0).toString() + '/10',
      (item.compositScore || 0).toString() + '/10',
      item.recommendation || '',
      item.founderName || '',
      new Date().toISOString()
    ]
  }
};

